using Expenses.Domain; using Microsoft.EntityFrameworkCore;
namespace Expenses.Persistence; /** <summary>Expense repository.</summary> */ public sealed class ExpenseRepository(ExpensesDbContext db):IExpenseRepository{private readonly ExpensesDbContext db=db??throw new ArgumentNullException(nameof(db));/** <inheritdoc/> */ public Task<Expense?> GetByIdAsync(Guid id,CancellationToken ct)=>db.Expenses.SingleOrDefaultAsync(x=>x.Id==id,ct);/** <inheritdoc/> */ public void Add(Expense e)=>db.Expenses.Add(e);/** <inheritdoc/> */ public void Remove(Expense e)=>db.Expenses.Remove(e);/** <inheritdoc/> */ public async Task SaveChangesAsync(CancellationToken ct)=>await db.SaveChangesAsync(ct).ConfigureAwait(false);}

